parameters.jsCode:
// Parse and validate the AI expectation check output.
const rawContent = $input.first().json?.message?.content
  || $input.first().json?.choices?.[0]?.message?.content
  || '';
const ctx = $('Execute Workflow Trigger').first().json;

let expectation_check;
try {
  const cleaned = rawContent.replace(/^```[a-z]*\n?|\n?```$/g, '').trim();
  expectation_check = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse expectation check JSON for ${ctx.topic_slug}/${ctx.date_key}: ${e.message}`);
}

// Validate required fields
if (!Array.isArray(expectation_check.expectations_checked)) {
  expectation_check.expectations_checked = [];
}
if (!Array.isArray(expectation_check.surprise_events)) {
  expectation_check.surprise_events = [];
}
if (typeof expectation_check.alignment_score !== 'number') {
  expectation_check.alignment_score = 50;
}

// Clamp and trim
expectation_check.alignment_score = Math.min(100, Math.max(0, Math.round(expectation_check.alignment_score)));
expectation_check.expectations_checked = expectation_check.expectations_checked.slice(0, 5).map(e => ({
  expectation: String(e.expectation || '').slice(0, 200),
  outcome: ['met', 'missed', 'partial'].includes(e.outcome) ? e.outcome : 'partial',
  note: e.note ? String(e.note).slice(0, 300) : null
}));
expectation_check.surprise_events = expectation_check.surprise_events.slice(0, 5).map(s => String(s).slice(0, 200));

return [{ json: { ...ctx, expectation_check } }];
